+/* ============================================================================
+   MARKDOWN WEB BROWSER - STRIPE-QUALITY UI
+   Modern, polished, professional design system
+   ============================================================================ */
+
+/* CSS Custom Properties - Design Tokens */
+:root {
+    /* Colors - Inspired by Stripe's design */
+    --color-primary: #635BFF;
+    --color-primary-hover: #0A2540;
+    --color-primary-light: #E8E7FF;
+    --color-success: #00D924;
+    --color-warning: #F5A623;
+    --color-error: #DF1B41;
+    --color-text-primary: #0A2540;
+    --color-text-secondary: #425466;
+    --color-text-tertiary: #6B7A8F; /* Improved from #8898AA for WCAG AA contrast (4.5:1) */
+    --color-bg-primary: #FFFFFF;
+    --color-bg-secondary: #F6F9FC;
+    --color-bg-tertiary: #E3E8EE;
+    --color-border: #E3E8EE;
+    --color-border-focus: #635BFF;
+
+    /* Shadows - Layered, subtle depth */
+    --shadow-sm: 0 1px 2px rgba(10, 37, 64, 0.035);
+    --shadow-md: 0 2px 5px rgba(10, 37, 64, 0.06), 0 1px 1px rgba(10, 37, 64, 0.05);
+    --shadow-lg: 0 4px 12px rgba(10, 37, 64, 0.08), 0 1px 3px rgba(10, 37, 64, 0.06);
+    --shadow-xl: 0 8px 24px rgba(10, 37, 64, 0.12), 0 2px 6px rgba(10, 37, 64, 0.08);
+
+    /* Border Radius */
+    --radius-sm: 4px;
+    --radius-md: 8px;
+    --radius-lg: 12px;
+    --radius-full: 9999px;
+
+    /* Spacing */
+    --spacing-xs: 4px;
+    --spacing-sm: 8px;
+    --spacing-md: 12px;
+    --spacing-lg: 16px;
+    --spacing-xl: 24px;
+    --spacing-2xl: 32px;
+
+    /* Typography */
+    --font-sans: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
+    --font-mono: "SF Mono", Monaco, "Cascadia Code", "Roboto Mono", Consolas, "Courier New", monospace;
+
+    /* Transitions */
+    --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
+    --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
+    --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);
+}
+
+/* Dark Mode Variables */
+@media (prefers-color-scheme: dark) {
+    :root {
+        --color-text-primary: #F6F9FC;
+        --color-text-secondary: #E3E8EE;
+        --color-text-tertiary: #8898AA;
+        --color-bg-primary: #0A2540;
+        --color-bg-secondary: #1A3A52;
+        --color-bg-tertiary: #2A4A62;
+        --color-border: #2A4A62;
+    }
+}
+
+/* Reset & Base */
+*, *::before, *::after {
+    margin: 0;
+    padding: 0;
+    box-sizing: border-box;
+}
+
+body {
+    font-family: var(--font-sans);
+    background: var(--color-bg-secondary);
+    color: var(--color-text-primary);
+    line-height: 1.5;
+    -webkit-font-smoothing: antialiased;
+    -moz-osx-font-smoothing: grayscale;
+    overflow: hidden;
+    height: 100vh;
+}
+
+/* Browser Container - Full Height Layout */
+.browser-container {
+    display: flex;
+    flex-direction: column;
+    height: 100vh;
+    background: var(--color-bg-primary);
+}
+
+/* ============================================================================
+   BROWSER CHROME (Toolbar)
+   ============================================================================ */
+
+.browser-chrome {
+    display: flex;
+    align-items: center;
+    gap: var(--spacing-md);
+    padding: var(--spacing-md) var(--spacing-lg);
+    background: var(--color-bg-primary);
+    border-bottom: 1px solid var(--color-border);
+    box-shadow: var(--shadow-sm);
+    z-index: 100;
+    position: relative;
+}
+
+/* Navigation Buttons */
+.nav-buttons {
+    display: flex;
+    gap: var(--spacing-xs);
+}
+
+.nav-btn {
+    width: 36px;
+    height: 36px;
+    border: 1px solid var(--color-border);
+    background: var(--color-bg-primary);
+    border-radius: var(--radius-md);
+    cursor: pointer;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    transition: border-color var(--transition-fast), opacity var(--transition-fast);
+    color: var(--color-text-primary);
+    position: relative;
+}
+
+.nav-btn::before {
+    content: '';
+    position: absolute;
+    inset: 0;
+    background: var(--color-primary);
+    opacity: 0;
+    border-radius: var(--radius-md);
+    transition: opacity var(--transition-fast);
+}
+
+.nav-btn:hover:not(:disabled)::before {
+    opacity: 0.06;
+}
+
+.nav-btn:active:not(:disabled)::before {
+    opacity: 0.12;
+}
+
+.nav-btn svg {
+    position: relative;
+    z-index: 1;
+}
+
+.nav-btn:disabled {
+    opacity: 0.4;
+    cursor: not-allowed;
+}
+
+/* Address Bar - Modern, Clean Design */
+.address-bar-container {
+    flex: 1;
+    display: flex;
+    max-width: 720px;
+}
+
+.address-bar {
+    flex: 1;
+    display: flex;
+    align-items: center;
+    background: var(--color-bg-secondary);
+    border: 1px solid var(--color-border);
+    border-radius: var(--radius-full);
+    padding: 0 var(--spacing-md) 0 var(--spacing-lg);
+    transition: all var(--transition-base);
+    position: relative;
+}
+
+.address-bar::before {
+    content: '';
+    position: absolute;
+    inset: -1px;
+    border-radius: var(--radius-full);
+    padding: 1px;
+    background: linear-gradient(135deg, var(--color-primary) 0%, var(--color-primary-hover) 100%);
+    -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
+    -webkit-mask-composite: xor;
+    mask-composite: exclude;
+    opacity: 0;
+    transition: opacity var(--transition-base);
+}
+
+.address-bar:focus-within {
+    background: var(--color-bg-primary);
+    box-shadow: var(--shadow-md);
+}
+
+.address-bar:focus-within::before {
+    opacity: 1;
+}
+
+.secure-icon {
+    font-size: 14px;
+    margin-right: var(--spacing-sm);
+    user-select: none;
+    filter: grayscale(20%);
+}
+
+.url-input {
+    flex: 1;
+    border: none;
+    outline: none;
+    font-size: 14px;
+    font-weight: 500;
+    padding: 10px var(--spacing-xs);
+    background: transparent;
+    font-family: var(--font-sans);
+    color: var(--color-text-primary);
+}
+
+.url-input::placeholder {
+    color: var(--color-text-tertiary);
+    font-weight: 400;
+}
+
+.go-btn {
+    width: 32px;
+    height: 32px;
+    border: none;
+    background: transparent;
+    cursor: pointer;
+    font-size: 18px;
+    font-weight: 600;
+    color: var(--color-primary);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    border-radius: 50%;
+    transition: all var(--transition-fast);
+}
+
+.go-btn:hover {
+    background: var(--color-primary-light);
+    transform: scale(1.1);
+}
+
+.go-btn:active {
+    transform: scale(0.95);
+}
+
+/* View Toggle - Modern Segmented Control */
+.view-toggle {
+    display: flex;
+    gap: 0;
+    background: var(--color-bg-secondary);
+    border: 1px solid var(--color-border);
+    border-radius: var(--radius-md);
+    padding: 2px;
+    position: relative;
+}
+
+.toggle-btn {
+    display: flex;
+    align-items: center;
+    gap: var(--spacing-sm);
+    padding: var(--spacing-sm) var(--spacing-lg);
+    border: none;
+    background: transparent;
+    border-radius: var(--radius-sm);
+    cursor: pointer;
+    font-size: 13px;
+    font-weight: 500;
+    color: var(--color-text-secondary);
+    transition: all var(--transition-base);
+    position: relative;
+    z-index: 1;
+}
+
+.toggle-btn:hover {
+    color: var(--color-text-primary);
+}
+
+.toggle-btn.active {
+    background: var(--color-bg-primary);
+    color: var(--color-primary);
+    box-shadow: var(--shadow-sm);
+}
+
+.toggle-btn svg {
+    width: 16px;
+    height: 16px;
+}
+
+/* ============================================================================
+   STATUS BAR
+   ============================================================================ */
+
+.status-bar {
+    display: flex;
+    align-items: center;
+    justify-content: space-between;
+    padding: var(--spacing-sm) var(--spacing-lg);
+    background: var(--color-bg-secondary);
+    border-bottom: 1px solid var(--color-border);
+    font-size: 12px;
+    color: var(--color-text-secondary);
+    min-height: 36px;
+    font-weight: 500;
+}
+
+.status-text {
+    flex: 1;
+    font-family: var(--font-mono);
+}
+
+/* Loading Spinner - Smooth Animation */
+.loading-spinner {
+    display: flex;
+    align-items: center;
+    gap: var(--spacing-sm);
+    color: var(--color-primary);
+}
+
+.spinner {
+    width: 14px;
+    height: 14px;
+    border: 2px solid var(--color-primary-light);
+    border-top-color: var(--color-primary);
+    border-radius: 50%;
+    animation: spin 0.6s linear infinite;
+}
+
+@keyframes spin {
+    to { transform: rotate(360deg); }
+}
+
+/* Progress Bar - Modern Gradient */
+.progress-container {
+    display: flex;
+    align-items: center;
+    gap: var(--spacing-md);
+    min-width: 200px;
+}
+
+.progress-bar {
+    flex: 1;
+    height: 4px;
+    background: var(--color-bg-tertiary);
+    border-radius: var(--radius-full);
+    overflow: hidden;
+    position: relative;
+}
+
+.progress-fill {
+    height: 100%;
+    background: linear-gradient(90deg, var(--color-primary) 0%, #00D924 100%);
+    border-radius: var(--radius-full);
+    transition: width var(--transition-slow);
+    position: relative;
+    overflow: hidden;
+}
+
+.progress-fill::after {
+    content: '';
+    position: absolute;
+    top: 0;
+    left: 0;
+    bottom: 0;
+    right: 0;
+    background: linear-gradient(90deg, transparent 0%, rgba(255,255,255,0.3) 50%, transparent 100%);
+    animation: shimmer 1.5s infinite;
+}
+
+@keyframes shimmer {
+    0% { transform: translateX(-100%); }
+    100% { transform: translateX(100%); }
+}
+
+.progress-text {
+    font-size: 11px;
+    font-weight: 600;
+    color: var(--color-text-secondary);
+    min-width: 40px;
+    text-align: right;
+    font-family: var(--font-mono);
+}
+
+/* ============================================================================
+   CONTENT AREA
+   ============================================================================ */
+
+.content-container {
+    flex: 1;
+    position: relative;
+    overflow: hidden;
+    background: var(--color-bg-primary);
+}
+
+.markdown-view {
+    position: absolute;
+    top: 0;
+    left: 0;
+    right: 0;
+    bottom: 0;
+    overflow: auto;
+    display: none;
+    padding: var(--spacing-2xl);
+    animation: fadeIn var(--transition-base);
+}
+
+@keyframes fadeIn {
+    from { opacity: 0; }
+    to { opacity: 1; }
+}
+
+.markdown-view.active {
+    display: block;
+}
+
+/* Rendered Markdown - Beautiful Typography */
+.markdown-body {
+    max-width: 760px;
+    margin: 0 auto;
+    padding: var(--spacing-2xl);
+    background: var(--color-bg-primary);
+    border-radius: var(--radius-lg);
+    box-shadow: var(--shadow-md);
+}
+
+.welcome-message {
+    padding: var(--spacing-2xl) 0;
+}
+
+.welcome-message h1 {
+    color: var(--color-text-primary);
+    margin-bottom: var(--spacing-lg);
+    font-size: 2.5em;
+    font-weight: 700;
+    letter-spacing: -0.02em;
+}
+
+.welcome-message h2 {
+    color: var(--color-text-primary);
+    margin-top: var(--spacing-2xl);
+    margin-bottom: var(--spacing-md);
+    font-size: 1.5em;
+    font-weight: 600;
+    letter-spacing: -0.01em;
+}
+
+.welcome-message p {
+    color: var(--color-text-secondary);
+    line-height: 1.6;
+    margin-bottom: var(--spacing-lg);
+    font-size: 1.05em;
+}
+
+.welcome-message ul,
+.welcome-message ol {
+    margin-left: var(--spacing-xl);
+    margin-bottom: var(--spacing-lg);
+}
+
+.welcome-message li {
+    margin-bottom: var(--spacing-sm);
+    line-height: 1.6;
+    color: var(--color-text-secondary);
+}
+
+.welcome-message em {
+    display: block;
+    margin-top: var(--spacing-2xl);
+    padding: var(--spacing-lg);
+    background: linear-gradient(135deg, var(--color-primary-light) 0%, #E8E7FF 100%);
+    border-left: 4px solid var(--color-primary);
+    border-radius: var(--radius-md);
+    font-style: normal;
+    font-weight: 500;
+    color: var(--color-text-primary);
+}
+
+/* Raw Markdown View - Code Editor Style */
+#raw-view pre {
+    margin: 0;
+    padding: var(--spacing-2xl);
+    background: #1E1E1E;
+    min-height: 100%;
+    font-size: 13px;
+    line-height: 1.6;
+    font-family: var(--font-mono);
+}
+
+#raw-view code {
+    font-family: var(--font-mono);
+}
+
+/* ============================================================================
+   ERROR VIEW
+   ============================================================================ */
+
+.error-view {
+    position: absolute;
+    top: 0;
+    left: 0;
+    right: 0;
+    bottom: 0;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    background: var(--color-bg-primary);
+    animation: fadeIn var(--transition-base);
+}
+
+.error-container {
+    text-align: center;
+    padding: var(--spacing-2xl);
+    max-width: 480px;
+    background: var(--color-bg-primary);
+    border-radius: var(--radius-lg);
+    box-shadow: var(--shadow-lg);
+}
+
+.error-icon {
+    font-size: 64px;
+    margin-bottom: var(--spacing-lg);
+    animation: bounce 0.5s ease;
+}
+
+@keyframes bounce {
+    0%, 100% { transform: translateY(0); }
+    50% { transform: translateY(-10px); }
+}
+
+.error-title {
+    font-size: 24px;
+    font-weight: 600;
+    color: var(--color-error);
+    margin-bottom: var(--spacing-md);
+    letter-spacing: -0.01em;
+}
+
+.error-message {
+    font-size: 15px;
+    color: var(--color-text-secondary);
+    line-height: 1.6;
+    margin-bottom: var(--spacing-xl);
+}
+
+.retry-btn {
+    padding: var(--spacing-md) var(--spacing-2xl);
+    background: var(--color-primary);
+    color: white;
+    border: none;
+    border-radius: var(--radius-md);
+    font-size: 14px;
+    font-weight: 600;
+    cursor: pointer;
+    transition: all var(--transition-fast);
+    box-shadow: var(--shadow-md);
+}
+
+.retry-btn:hover {
+    background: var(--color-primary-hover);
+    box-shadow: var(--shadow-lg);
+    transform: translateY(-1px);
+}
+
+.retry-btn:active {
+    transform: translateY(0);
+    box-shadow: var(--shadow-sm);
+}
+
+/* ============================================================================
+   CUSTOM SCROLLBAR
+   ============================================================================ */
+
+.markdown-view::-webkit-scrollbar {
+    width: 10px;
+}
+
+.markdown-view::-webkit-scrollbar-track {
+    background: var(--color-bg-secondary);
+}
+
+.markdown-view::-webkit-scrollbar-thumb {
+    background: var(--color-border);
+    border-radius: var(--radius-full);
+    border: 2px solid var(--color-bg-secondary);
+}
+
+.markdown-view::-webkit-scrollbar-thumb:hover {
+    background: var(--color-text-tertiary);
+}
+
+/* ============================================================================
+   RESPONSIVE DESIGN
+   ============================================================================ */
+
+@media (max-width: 768px) {
+    .browser-chrome {
+        flex-wrap: wrap;
+        padding: var(--spacing-sm);
+    }
+
+    .address-bar-container {
+        order: 3;
+        width: 100%;
+        margin-top: var(--spacing-sm);
+        max-width: none;
+    }
+
+    .toggle-btn span {
+        display: none;
+    }
+
+    .markdown-view {
+        padding: var(--spacing-lg);
+    }
+
+    .markdown-body {
+        padding: var(--spacing-lg);
+    }
+
+    .welcome-message h1 {
+        font-size: 2em;
+    }
+}
+
+/* ============================================================================
+   ACCESSIBILITY
+   ============================================================================ */
+
+.nav-btn:focus-visible,
+.go-btn:focus-visible,
+.toggle-btn:focus-visible,
+.retry-btn:focus-visible {
+    outline: 2px solid var(--color-primary);
+    outline-offset: 2px;
+}
+
+.url-input:focus-visible {
+    outline: none;
+}
+
+/* Reduced motion support */
+@media (prefers-reduced-motion: reduce) {
+    *,
+    *::before,
+    *::after {
+        animation-duration: 0.01ms !important;
+        animation-iteration-count: 1 !important;
+        transition-duration: 0.01ms !important;
+    }
+}

